FROM jsonb_to_recordset('[{"id": "cap-114-society-029", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "小綸從網站上取得2021年中國各省級行政區年降水量資料，他以當年全國平\n均降水量691.6毫米作為標準，若省級行政區的年降水量低於此一數值，則在\n該區塗上深灰色。根據上述原則，小綸繪製出的地圖最可能為下列何者？", "options": ["", "", "", ""], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 29, "raw_text": "29. 小綸從網站上取得2021年中國各省級行政區年降水量資料，他以當年全國平\n    均降水量691.6毫米作為標準，若省級行政區的年降水量低於此一數值，則在\n    該區塗上深灰色。根據上述原則，小綸繪製出的地圖最可能為下列何者？\n    (A)        (B)      (C)     (D)\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-society-030", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "碳匯是指能夠吸收及儲存含碳化合物的天然或人工「倉庫」，如森林、草\n原、濕地、土壤、海洋等。為了達成2050年「碳中和」目標，各國除了減少\n二氧化碳的排放之外，也積極擴大國家的碳匯。根據上文所述，若要增加一\n國的碳匯，則下列何種方法最為適切？", "options": ["以焚林的方式，快速取得種植經濟作物的土地", "於屋頂上方設置太陽能發電板，增加電力供給", "恢復曾經消失的農地，採友善環境的耕作方式", "選用當地食材以減少運輸距離，降低食物里程"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 30, "raw_text": "30. 碳匯是指能夠吸收及儲存含碳化合物的天然或人工「倉庫」，如森林、草\n    原、濕地、土壤、海洋等。為了達成2050年「碳中和」目標，各國除了減少\n    二氧化碳的排放之外，也積極擴大國家的碳匯。根據上文所述，若要增加一\n    國的碳匯，則下列何種方法最為適切？\n    (A)以焚林的方式，快速取得種植經濟作物的土地\n    (B)於屋頂上方設置太陽能發電板，增加電力供給\n    (C)恢復曾經消失的農地，採友善環境的耕作方式\n    (D)選用當地食材以減少運輸距離，降低食物里程\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "碳匯指能吸收與儲存碳的「倉庫」。(C)「恢復農地、採友善環境耕作」可恢復土壤與植被的碳吸存功能，直接擴大碳匯，故 (C) 正確。(A) 焚林釋出二氧化碳並破壞既有碳匯；(B) 太陽能屬減排（減少新增），不增加碳匯；(D) 降低食物里程同樣屬減排。"}, {"id": "cap-114-society-031", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "莎 綺 去 北 大 武 山 登 山 的 時 候 ，\n看到山路上有一些歷史建築如\n圖(十五)所示。根據圖中碑文\n摘譯的內容判斷，若莎綺上網\n檢索這些歷史建築興建的時\n局背景，最可能會出現下列\n何者？", "options": ["強化皇民化運動的推展", "宣傳日 俄戰爭即將勝利", "實施開山撫番推動漢化", "發起原住民族正名運動 圖(十五)"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 31, "raw_text": "31. 莎 綺 去 北 大 武 山 登 山 的 時 候 ，\n    看到山路上有一些歷史建築如\n    圖(十五)所示。根據圖中碑文\n    摘譯的內容判斷，若莎綺上網\n    檢索這些歷史建築興建的時\n    局背景，最可能會出現下列\n    何者？\n    (A)強化皇民化運動的推展\n    (B)宣傳日 俄戰爭即將勝利\n    (C)實施開山撫番推動漢化\n    (D)發起原住民族正名運動\n                                             圖(十五)\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-society-032", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "理加頭目所屬部落與鄰近部落衝突頻繁，而荷蘭人未能妥善協助調停，心生不滿\n的他在日本人勸說下，帶族人前往日本尋求援助。理加返鄉後，立即遭到荷蘭人\n的監禁，進而引發日人挾持臺灣長官的衝突事件，更導致江戶幕府一度關閉荷蘭\n在日本的商館以作為制裁。上述事件最可能發生於下列何時何地？", "options": ["十六世紀的澎湖 &江\u0007戶幕府：明治天皇親政以前，", "十七世紀的大員            實際統治日本的機構。", "十八世紀的淡水", "十九世紀的卑南 表(四)"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 32, "raw_text": "32. 理加頭目所屬部落與鄰近部落衝突頻繁，而荷蘭人未能妥善協助調停，心生不滿\n    的他在日本人勸說下，帶族人前往日本尋求援助。理加返鄉後，立即遭到荷蘭人\n    的監禁，進而引發日人挾持臺灣長官的衝突事件，更導致江戶幕府一度關閉荷蘭\n    在日本的商館以作為制裁。上述事件最可能發生於下列何時何地？\n    (A)十六世紀的澎湖\n                        &江\u0007戶幕府：明治天皇親政以前，\n    (B)十七世紀的大員            實際統治日本的機構。\n    (C)十八世紀的淡水\n    (D)十九世紀的卑南\n\n                                              表(四)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-society-033", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "表(四)是某一時期臺灣鳳梨罐                貿易\n頭銷售至美國、日本、中國大                 對象\n甲      乙       丙       丁\n陸及西德的官方統計數據。根               年分\n據表中內容判斷，甲、乙、\n1946         0       0       0 60,696\n丙、丁何者最可能是中國大\n1950    38,134     203       0      0\n陸？\n1955   182,000 33,836 153,963       0", "options": ["甲", "乙 1960   269,338 676,098 737,723      0", "丙", "丁 單位：箱"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 33, "raw_text": "33. 表(四)是某一時期臺灣鳳梨罐                貿易\n    頭銷售至美國、日本、中國大                 對象\n                                         甲      乙       丙       丁\n    陸及西德的官方統計數據。根               年分\n    據表中內容判斷，甲、乙、\n                                1946         0       0       0 60,696\n    丙、丁何者最可能是中國大\n                                1950    38,134     203       0      0\n    陸？\n                                1955   182,000 33,836 153,963       0\n    (A)甲     (B)乙\n                                1960   269,338 676,098 737,723      0\n    (C)丙     (D)丁\n                                                              單位：箱\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-society-034", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "圖(十六)是某大學公布欄所張貼的海報，根據圖中\n所列的演講者經歷判斷，下列何者最可能是他曾經\n行使過的職權？", "options": ["為審核各機關送交的決算挑燈夜戰", "提請總統任命行政院所屬部會首長", "對司法院院長被提名人行使同意權 (D)在掌握事證後彈劾違法失職的法官                                圖(十六)", ""], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 34, "raw_text": "34. 圖(十六)是某大學公布欄所張貼的海報，根據圖中\n    所列的演講者經歷判斷，下列何者最可能是他曾經\n    行使過的職權？\n    (A)為審核各機關送交的決算挑燈夜戰\n    (B)提請總統任命行政院所屬部會首長\n    (C)對司法院院長被提名人行使同意權\n    (D)在掌握事證後彈劾違法失職的法官                                圖(十六)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-society-035", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "甲、乙二則資料呈現不同時代官方興建公共建設的相關情況：\n甲資料：統治者為了加強對國內各地的控制，便於運送物資及兵力，下令修\n鑿運河，強行徵召數百萬人民從事勞役。\n乙資料：某地方政府研擬興建社會住宅，當地議會要求依法召開公聽會聽取\n附近居民的意見，作為後續制定政策的參考。\n根據甲、乙二項資料判斷，關於不同時代官方興建公共建設作法的敘述，\n下列何者最適當？", "options": ["甲資料顯示當時的市場勞動權利受法律保障", "乙資料顯示當時的政府權力受到約束與制衡", "二則資料皆顯示公共建設以促進公平正義為主要考量", "二則資料皆顯示公共意見是經由大眾反覆討論而形成"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 35, "raw_text": "35. 甲、乙二則資料呈現不同時代官方興建公共建設的相關情況：\n    甲資料：統治者為了加強對國內各地的控制，便於運送物資及兵力，下令修\n          鑿運河，強行徵召數百萬人民從事勞役。\n    乙資料：某地方政府研擬興建社會住宅，當地議會要求依法召開公聽會聽取\n          附近居民的意見，作為後續制定政策的參考。\n    根據甲、乙二項資料判斷，關於不同時代官方興建公共建設作法的敘述，\n    下列何者最適當？\n    (A)甲資料顯示當時的市場勞動權利受法律保障\n    (B)乙資料顯示當時的政府權力受到約束與制衡\n    (C)二則資料皆顯示公共建設以促進公平正義為主要考量\n    (D)二則資料皆顯示公共意見是經由大眾反覆討論而形成\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "乙資料中議會「依法召開公聽會聽取居民意見」顯示行政部門受到立法部門及法定程序的監督，正是政府權力受約束與制衡的展現，故 (B) 正確。(A) 甲資料是強徵勞役、勞動權未受保障；(C) 甲為強制非為公平正義；(D) 甲屬統治者單方決定，非反覆討論形成。"}, {"id": "cap-114-society-036", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "老師安排同學至地方法院參觀，並讓甲、\n乙、丙、丁四位同學在模擬法庭中扮演不同\n的角色，如圖(十七)所示。根據我國法律規\n定及圖中情境判斷，下列關於他們四人的臺\n詞，何者最適當？", "options": ["甲：我依據相關犯罪事證依法起訴乙", "乙：我承認錯誤，我會儘早償還借款", "丙：我希望甲審酌證據後判決乙無罪", "丁：我判決原告勝訴，撤銷行政處分 圖(十七)"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 36, "raw_text": "36. 老師安排同學至地方法院參觀，並讓甲、\n    乙、丙、丁四位同學在模擬法庭中扮演不同\n    的角色，如圖(十七)所示。根據我國法律規\n    定及圖中情境判斷，下列關於他們四人的臺\n    詞，何者最適當？\n    (A)甲：我依據相關犯罪事證依法起訴乙\n    (B)乙：我承認錯誤，我會儘早償還借款\n    (C)丙：我希望甲審酌證據後判決乙無罪\n    (D)丁：我判決原告勝訴，撤銷行政處分\n                            圖(十七)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-society-037", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "「社會企業」是近年頗受關注的概念，其中公司型的社會企業透過商業活動營\n利，以改善社會或環境問題為目標，並非以讓出資者獲利為唯一考量，而企業\n獲得的利潤，也將繼續投入改善社會或環境問題的商業活動，希望讓社會企業\n得以永續經營。下列何種作法與上述提及的企業經營模式最相符？", "options": ["運用低價策略創造企業優勢", "制定法律推行友善勞工政策", "提倡公平貿易幫助小農發展", "募集善心捐款扶助弱勢群體"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 37, "raw_text": "37. 「社會企業」是近年頗受關注的概念，其中公司型的社會企業透過商業活動營\n    利，以改善社會或環境問題為目標，並非以讓出資者獲利為唯一考量，而企業\n    獲得的利潤，也將繼續投入改善社會或環境問題的商業活動，希望讓社會企業\n    得以永續經營。下列何種作法與上述提及的企業經營模式最相符？\n    (A)運用低價策略創造企業優勢\n    (B)制定法律推行友善勞工政策\n    (C)提倡公平貿易幫助小農發展\n    (D)募集善心捐款扶助弱勢群體\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "社會企業以商業手段解決社會問題、利潤再投入社會目的。(C) 推行公平貿易協助小農，正是透過商業活動同時改善生產者處境，故 (C) 正確。(A) 低價策略以營利為核心；(B) 立法為政府職能；(D) 募款扶助屬慈善而非商業營利模式。"}, {"id": "cap-114-society-038", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "某日新聞報導有位失智症患者將土地、房屋贈送給陌生人的糾紛，由於小明\n的爺爺是中度失智症患者，家人擔心爺爺也會做出類似行為而導致權益受\n損，便向律師諮詢。律師建議家屬可向法院提出聲請，對爺爺作出監護宣\n告。上述律師的建議內容應是希望達成下列何項法律效果？", "options": ["讓爺爺成為無行為能力人，以保障其財產", "讓爺爺成為限制行為能力人，以保障其財產", "讓爺爺成為無行為能力人，以保障其契約自由", "讓爺爺成為限制行為能力人，以保障其契約自由"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 38, "raw_text": "38. 某日新聞報導有位失智症患者將土地、房屋贈送給陌生人的糾紛，由於小明\n    的爺爺是中度失智症患者，家人擔心爺爺也會做出類似行為而導致權益受\n    損，便向律師諮詢。律師建議家屬可向法院提出聲請，對爺爺作出監護宣\n    告。上述律師的建議內容應是希望達成下列何項法律效果？\n    (A)讓爺爺成為無行為能力人，以保障其財產\n    (B)讓爺爺成為限制行為能力人，以保障其財產\n    (C)讓爺爺成為無行為能力人，以保障其契約自由\n    (D)讓爺爺成為限制行為能力人，以保障其契約自由\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "監護宣告是法院認定受宣告人不能辨識其意思表示效果，使其成為「無行為能力人」，所為法律行為原則上無效，藉此防止其因失智被詐取財產，故 (A) 正確。(B)(D) 限制行為能力人對應的是輔助宣告；(C) 監護宣告反而限縮契約自由，目的在保障財產而非契約自由。"}, {"id": "cap-114-society-039", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "2020年之前，臺灣與日本都面臨勞力短缺的問題，但日本提供比臺灣更高的\n薪資吸引國際移工，因此許多菲律賓籍移工較願意前往日本工作。不過2022\n年底時，許多在日本工作的菲律賓籍移工發現，雖然每個月都拿出相同金額\n的日幣兌換成菲律賓披索匯回家鄉，但年底換到的菲律賓披索卻比年初減少\n了約10%，因此他們打算改往澳洲工作。上述國際移工變更工作地的考量，\n其原因之一最可能為下列何者？", "options": ["菲律賓披索相對日幣升值 & 菲律賓披索：菲律賓貨幣名稱。", "菲律賓披索相對新臺幣貶值", "去臺灣工作的機會成本比去日本低", "去澳洲工作的機會成本比去日本高"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 39, "raw_text": "39. 2020年之前，臺灣與日本都面臨勞力短缺的問題，但日本提供比臺灣更高的\n    薪資吸引國際移工，因此許多菲律賓籍移工較願意前往日本工作。不過2022\n    年底時，許多在日本工作的菲律賓籍移工發現，雖然每個月都拿出相同金額\n    的日幣兌換成菲律賓披索匯回家鄉，但年底換到的菲律賓披索卻比年初減少\n    了約10%，因此他們打算改往澳洲工作。上述國際移工變更工作地的考量，\n    其原因之一最可能為下列何者？\n    (A)菲律賓披索相對日幣升值\n                         & 菲律賓披索：菲律賓貨幣名稱。\n    (B)菲律賓披索相對新臺幣貶值\n    (C)去臺灣工作的機會成本比去日本低\n    (D)去澳洲工作的機會成本比去日本高\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "原文「相同金額的日幣兌換到的披索較年初減少約 10%」，等量日幣換得較少披索，代表披索相對日幣變值錢、即升值，故 (A) 正確。(B) 與新臺幣的相對變化不在文中比較範圍；(C)(D) 機會成本敘述方向與題意「換不到等值披索」無關。"}, {"id": "cap-114-society-040", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "「 俄 烏 戰 爭 以 來 ， 歐 盟 對\n俄羅斯採取大規模的制裁措\n施，其中立陶宛於2022年6月\n18日，對經其領土進出俄羅\n斯 加里寧格勒的貨運火車實\n施限制，因而引發俄羅斯強\n烈不滿。此一事件也凸顯出\n加里寧格勒的重要性。」圖\n(十八)顯示加里寧格勒的位\n置，根據上文及圖中資訊判\n斷，其重要性可用下列何者\n來說明？\n圖(十八)", "options": ["作為俄羅斯與東北亞國家間的貿易前哨站", "為俄羅斯貨物經波羅的海出太平洋的港口", "位處俄羅斯天然氣輸送至芬蘭的最短路徑上", "是俄羅斯對抗北大西洋公約組織的軍事基地"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 40, "raw_text": "40. 「 俄 烏 戰 爭 以 來 ， 歐 盟 對\n    俄羅斯採取大規模的制裁措\n    施，其中立陶宛於2022年6月\n    18日，對經其領土進出俄羅\n    斯 加里寧格勒的貨運火車實\n    施限制，因而引發俄羅斯強\n    烈不滿。此一事件也凸顯出\n    加里寧格勒的重要性。」圖\n    (十八)顯示加里寧格勒的位\n    置，根據上文及圖中資訊判\n    斷，其重要性可用下列何者\n    來說明？\n                                   圖(十八)\n    (A)作為俄羅斯與東北亞國家間的貿易前哨站\n    (B)為俄羅斯貨物經波羅的海出太平洋的港口\n    (C)位處俄羅斯天然氣輸送至芬蘭的最短路徑上\n    (D)是俄羅斯對抗北大西洋公約組織的軍事基地\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-society-041", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "表(五)為三個不同日期臺灣部分水              表(五)\n庫的蓄水量百分比，這些水庫在                   蓄水量百分比 (%)\n所在\n2021年5月31日的蓄水量狀況，可 水庫名稱        2020年 2020年 2021年\n行政區\n能與下列何者關係最為密切？                  5月31日 11月30日 5月31日", "options": ["2021年梅雨鋒面提早報到     翡翠水庫 新北市 80.9    94.6  62.1", "2021年夏末對流雨較不旺盛    石門水庫 桃園市 67.4    49.7  12.5", "2020年冬季迎風面的地形雨偏少 鯉魚潭水庫 苗栗縣 53.7    39.4   5.8", "2020年缺乏颱風帶來的豐沛雨量 德基水庫 臺中市 42.7    38.2   2.7 嘉義縣 曾文水庫      27.7   23.1   4.1 臺南市"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 41, "raw_text": "41. 表(五)為三個不同日期臺灣部分水              表(五)\n    庫的蓄水量百分比，這些水庫在                   蓄水量百分比 (%)\n                               所在\n    2021年5月31日的蓄水量狀況，可 水庫名稱        2020年 2020年 2021年\n                               行政區\n    能與下列何者關係最為密切？                  5月31日 11月30日 5月31日\n    (A) 2021年梅雨鋒面提早報到     翡翠水庫 新北市 80.9    94.6  62.1\n    (B) 2021年夏末對流雨較不旺盛    石門水庫 桃園市 67.4    49.7  12.5\n    (C) 2020年冬季迎風面的地形雨偏少 鯉魚潭水庫 苗栗縣 53.7    39.4   5.8\n    (D) 2020年缺乏颱風帶來的豐沛雨量\n                          德基水庫 臺中市 42.7    38.2   2.7\n                               嘉義縣\n                          曾文水庫      27.7   23.1   4.1\n                               臺南市\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-society-042", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-114-society", "question_type": "single_choice", "question_text": "某民意代表在服務處設立法律諮詢服務站，表(六)          表(六)\n是2020年及2021年法律諮詢服務件數的統計資料，      時間 2020 2021\n在2020年的刑事案件中，超過半數屬於告訴乃論，     類型     年    年\n而2021年則有過半數的刑事案件屬於非告訴乃論。     民事事件   200   230\n根據上述內容判斷，在2020年及2021年的諮詢服務   刑事案件   180   150\n中，可採調解方式處理的件數可能為下列何者？        法律諮詢", "options": ["2020年70件，2021年100件              380   380 服務總數", "2020年100件，2021年70件                 單位：件", "2020年300件，2021年300件", "2020年330件，2021年330件"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:26+00:00", "source_pdf_sha1": "a2859bc348a7", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 42, "raw_text": "42. 某民意代表在服務處設立法律諮詢服務站，表(六)          表(六)\n    是2020年及2021年法律諮詢服務件數的統計資料，      時間 2020 2021\n    在2020年的刑事案件中，超過半數屬於告訴乃論，     類型     年    年\n    而2021年則有過半數的刑事案件屬於非告訴乃論。     民事事件   200   230\n    根據上述內容判斷，在2020年及2021年的諮詢服務   刑事案件   180   150\n    中，可採調解方式處理的件數可能為下列何者？        法律諮詢\n    (A) 2020年70件，2021年100件              380   380\n                                 服務總數\n    (B) 2020年100件，2021年70件                 單位：件\n    (C) 2020年300件，2021年300件\n    (D) 2020年330件，2021年330件\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
